import { findAyahIdBySurah } from "./findAyahIdBySurah.mjs";
import { findManzilByAyahId } from "./findManzilByAyahId.mjs";

//#region src/findManzil.ts
/**
* Finds the Manzil number for a given Surah and Ayah
* @param surah - The Surah number or object
* @param ayah - Optional Ayah number (defaults to 1)
* @param data - The Lists object for the riwaya.
* @returns The Manzil number (1-7) containing the specified Ayah
*/
function findManzil(surah, ayah = 1, data) {
	return findManzilByAyahId(findAyahIdBySurah(surah, ayah, data), data);
}

//#endregion
export { findManzil };